import java.util.ArrayList;
import java.util.Arrays;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

class Solution {
    public List<List<String>> groupAnagrams(String[] strs) {
        if (strs == null || strs.length == 0) {
            return new ArrayList<>();
        }

        // Use a HashMap to store groups of anagrams.
        // The key will be the sorted version of a string (canonical form).
        // The value will be a list of original strings that are anagrams.
        Map<String, List<String>> anagramGroups = new HashMap<>();

        for (String str : strs) {
            // Convert the string to a character array to sort it.
            char[] charArray = str.toCharArray();
            // Sort the character array. This creates the canonical form.
            Arrays.sort(charArray);
            // Convert the sorted character array back to a string.
            String sortedStr = new String(charArray);

            // If the sorted string (key) is not yet in the map,
            // create a new list for it.
            if (!anagramGroups.containsKey(sortedStr)) {
                anagramGroups.put(sortedStr, new ArrayList<>());
            }
            // Add the original string to the list associated with its sorted form.
            anagramGroups.get(sortedStr).add(str);
        }

        // The result is a list of all the lists stored as values in the map.
        return new ArrayList<>(anagramGroups.values());
    }
}
