class Solution {
    public int findMaxConsecutiveOnes(int[] nums) {
        int maxCount = 0; // 用于存储全局最大连续1的个数
        int currentCount = 0; // 用于存储当前连续1的个数

        for (int num : nums) {
            if (num == 1) {
                currentCount++; // 如果是1，当前连续计数增加
            } else {
                // 如果是0，说明连续1中断了
                // 在重置currentCount之前，先将当前连续计数与全局最大计数比较，更新maxCount
                maxCount = Math.max(maxCount, currentCount);
                currentCount = 0; // 重置当前连续计数
            }
        }

        // 循环结束后，需要再次比较一次。因为如果数组以一个或多个1结尾，
        // 那么最后一个currentCount可能还没有被用来更新maxCount。
        maxCount = Math.max(maxCount, currentCount);

        return maxCount;
    }
}
