        while (left < right) {
            int currentSum = numbers[left] + numbers[right];
            if (currentSum == target) {
                // Problem asks for 1-indexed output
                return new int[]{left + 1, right + 1};
            } else if (currentSum < target) {
                left++; // Need a larger sum, move left pointer right
            } else { // currentSum > target
                right--; // Need a smaller sum, move right pointer left
            }
        }
        // According to the problem description, there will always be exactly one solution.
        // This line should ideally not be reached if the input guarantees are met.
        return new int[]{-1, -1}; 
    }
