import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

class Solution {
    public List<List<Integer>> threeSum(int[] nums) {
        List<List<Integer>> result = new ArrayList<>();
        if (nums == null || nums.length < 3) {
            return result;
        }

        Arrays.sort(nums); // Sort the array to easily handle duplicates and use two-pointer technique

        int n = nums.length;
        for (int i = 0; i < n - 2; i++) {
            // Skip duplicate for the first element
            if (i > 0 && nums[i] == nums[i - 1]) {
                continue;
            }

            // Optimization: if nums[i] is already positive, sum cannot be zero with other positive numbers
            if (nums[i] > 0) {
                break;
            }

            int left = i + 1;
            int right = n - 1;
            int target = -nums[i]; // We need nums[left] + nums[right] == -nums[i]

            while (left < right) {
                int sum = nums[left] + nums[right];

                if (sum == target) {
                    result.add(Arrays.asList(nums[i], nums[left], nums[right]));

                    // Skip duplicates for left pointer
                    while (left < right && nums[left] == nums[left + 1]) {
                        left++;
                    }
                    // Skip duplicates for right pointer
                    while (left < right && nums[right] == nums[right - 1]) {
                        right--;
                    }

                    left++;
                    right--;
                } else if (sum < target) {
                    left++;
                } else { // sum > target
                    right--;
                }
            }
        }

        return result;
    }
}
