```java
class WalkingRobot {
    private int width;
    private int height;
    private int x;
    private int y;
    private int dirIdx; // 0: East (1,0), 1: North (0,1), 2: West (-1,0), 3: South (0,-1)
    private boolean started; // Flag to track if step() has been called at least once

    // Directions: East, North, West, South
    private static final int[][] DIRS = {{1, 0}, {0, 1}, {-1, 0}, {0, -1}};

    public WalkingRobot(int width, int height) {
        this.width = width;
        this.height = height;
        this.x = 0;
        this.y = 0;
        this.dirIdx = 0; // Initially East
        this.started = false;
    }

    public void step(int num) {
        this.started = true;

        while (num > 0) {
            int stepsToWall;
            // Calculate steps remaining to hit a wall in the current direction
            if (dirIdx == 0) { // East
                stepsToWall = width - 1 - x;
            } else if (dirIdx == 1) { // North
                stepsToWall = height - 1 - y;
            } else if (dirIdx == 2) { // West
                stepsToWall = x - 0; // Distance to left wall (x=0)
            } else { // dirIdx == 3, South
                stepsToWall = y - 0; // Distance to bottom wall (y=0)
            }

            // Determine how many steps to actually take in this segment
            // We take min(remaining_steps_in_num, steps_to_wall)
            int actualSteps = Math.min(num, stepsToWall);

            // Move the robot
            x += actualSteps * DIRS[dirIdx][0];
            y += actualSteps * DIRS[dirIdx][1];
            num -= actualSteps;

            // If there are still steps left (num > 0), it means we hit a wall and need to turn
            if (num > 0) {
                dirIdx = (dirIdx + 1) % 4; // Turn 90 degrees clockwise
            }
        }
    }

    public void turnLeft() {
        // Turn 90 degrees counter-clockwise
        dirIdx = (dirIdx + 1) % 4;
    }

    public void turnRight() {
        // Turn 90 degrees clockwise
        // (dirIdx - 1 + 4) % 4 ensures positive result for modulo with negative numbers
        dirIdx = (dirIdx + 3) % 4;
    }

    public int[] getPos() {
        return new int[]{x, y};
    }

    public int[] getDir() {
        // If not started, direction is considered East
        if (!started) {
            return DIRS[0]; // East
        }
        return DIRS[dirIdx];
    }
}
