Longest Repeating Character Replacement.solution:
```java
class Solution {
    public int characterReplacement(String s, int k) {
        // freq 数组用于记录当前窗口内每个字符的出现次数
        int[] freq = new int[26];
        // maxFreq 记录当前窗口内（或历史窗口中）出现过的最大字符频率
        int maxFreq = 0;
        // maxLength 记录找到的最长有效窗口的长度
        int maxLength = 0;
        // left 是滑动窗口的左边界
        int left = 0;

        // right 是滑动窗口的右边界，遍历字符串
        for (int right = 0; right < s.length(); right++) {
            char currentChar = s.charAt(right);
            // 增加当前字符的频率计数
            freq[currentChar - 'A']++;
            // 更新 maxFreq，它始终是当前窗口内出现频率最高的字符的频率
            // 注意：这里 maxFreq 实际上是记录了从窗口开始到当前 right 为止，
            // 任何一个字符在某个时刻达到的最大频率。它不一定严格代表当前 [left, right] 窗口的最大频率。
            // 这种处理方式是 O(N) 复杂度的关键。
            maxFreq = Math.max(maxFreq, freq[currentChar - 'A']);

            // 计算当前窗口的长度
            int windowLength = right - left + 1;
            // 判断当前窗口是否有效：
            // 如果 (窗口长度 - 窗口内出现次数最多的字符的频率) > k，
            // 说明需要替换的字符数量超过了 k，窗口无效，需要缩小。
            if (windowLength - maxFreq > k) {
                char leftChar = s.charAt(left);
                // 缩小窗口，将左边界字符的频率减一
                freq[leftChar - 'A']--;
                // 左边界右移
                left++;
                // 注意：这里不需要重新计算 maxFreq。因为我们只关心最长窗口，
                // 如果 maxFreq 减小，意味着当前窗口“纯度”降低，
                // 即使窗口长度不变，也无法形成更长的有效窗口。
                // 只有当 maxFreq 增加时，才可能形成更长的有效窗口。
            }

            // 无论窗口是否缩小，当前 [left, right] 都是一个有效的（或刚刚调整为有效的）窗口。
            // 更新 maxLength，取当前窗口长度和之前最大长度的较大值。
            maxLength = Math.max(maxLength, right - left + 1);
        }

        return maxLength;
    }
}
